1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return an empty set of living cells when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single living cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill a living cell with only one living neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a living cell alive with two living neighbors", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [-1, 0]])).toContainEqual([0, 0]);
16	  });
17	  it("should keep a living cell alive with three living neighbors", () => {
18	    expect(nextGeneration([[0, 0], [1, 0], [-1, 0], [0, 1]])).toContainEqual([0, 0]);
19	  });
20	  it("should kill a living cell with four living neighbors (overpopulation)", () => {
21	    expect(nextGeneration([[0, 0], [1, 0], [-1, 0], [0, 1], [0, -1]])).not.toContainEqual([0, 0]);
22	  });
23	  it.todo("should bring a dead cell to life when it has exactly three living neighbors (reproduction)");
24	  it.todo("should handle living cells with negative coordinates");
25	});
26

1	export type Cell = readonly [number, number];
2	
3	const isNeighbor = (cell: Cell, other: Cell): boolean => {
4	  const [x, y] = cell;
5	  const [ox, oy] = other;
6	  return Math.max(Math.abs(ox - x), Math.abs(oy - y)) === 1;
7	};
8	
9	const countLivingNeighbors = (cell: Cell, livingCells: readonly Cell[]): number =>
10	  livingCells.filter((other) => isNeighbor(cell, other)).length;
11	
12	const survives = (neighbors: number): boolean => neighbors === 2 || neighbors === 3;
13	
14	export const nextGeneration = (livingCells: readonly Cell[]): Cell[] =>
15	  livingCells.filter((cell) => survives(countLivingNeighbors(cell, livingCells)));
